 uv_1 = (mix (uv_orig, uv, vec2((
   clamp ((((bass / bass_att) - 0.9) * 13.0), 0.0, 1.0)
  * 0.5))) + ((
   (tmpvar_2 * texsize.zw)
  * 
   cos(((rad * 30.0) - tmpvar_3))
 ) * 5.0));
 uv_1 = (uv_1 + ((
   (vec2(5.0, -5.0) * texsize.zw)
  * 
   cos(((ang * 30.0) - tmpvar_3))
 ) * tmpvar_2.yx));
 vec4 tmpvar_4;
 tmpvar_4.w = 1.0;
 tmpvar_4.xyz = ((texture (sampler_main, uv_1).xyz - 0.04) * 0.7);
 ret = tmpvar_4.xyz;
}

